import random
import time

class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 0
        self.direction = None
        self.passengers = []

    def move(self):
        if self.direction == 'up':
            self.current_floor += 1
        elif self.direction == 'down':
            self.current_floor -= 1

    def call_lift(self, floor, direction):
        self.direction = direction
        self.current_floor = floor

    def load_passengers(self, passengers):
        self.passengers.extend(passengers)

    def unload_passengers(self):
        self.passengers = []

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i) for i in range(num_lifts)]
        self.passenger_requests = []

    def request_lift(self, floor, direction):
        self.passenger_requests.append((floor, direction))

    def simulate(self, hours, crowd_size):
        for hour in range(hours):
            print(f"Hour: {hour}")
            if hour < 9 or hour >= 17:  # Morning and evening rush hours
                self.generate_requests(crowd_size)
            else:  # Daytime
                self.generate_requests(crowd_size // 4)

            for lift in self.lifts:
                if self.passenger_requests:
                    floor, direction = self.passenger_requests.pop(0)
                    lift.call_lift(floor, direction)
                    lift.load_passengers([f"Passenger {i}" for i in range(random.randint(1, 5))])
                    lift.move()
                    print(f"Lift {lift.id} moving to floor {lift.current_floor} with passengers: {lift.passengers}")
                    lift.unload_passengers()

            time.sleep(1)  # Simulate time passing

    def generate_requests(self, crowd_size):
        for _ in range(crowd_size):
            floor = random.randint(0, self.num_floors - 1)
            direction = random.choice(['up', 'down'])
            self.request_lift(floor, direction)

if __name__ == "__main__":
    building = Building(num_floors=20, num_lifts=5)
    building.simulate(hours=12, crowd_size=20)

